-- ═══════════════════════════════════════════════════════════════════════════════
-- adventure.lua — game module for the Archipelago BizHawk connector.
--                 Adventure (Atari 2600)
--
-- SOURCE: worlds/adventure (Locations.py, Offsets.py, __init__.py, Rom.py) +
--   the OFFICIAL BizHawk connector data/lua/connector_adventure.lua, AP main
--   branch. The detectable location id list and the dragon-slay mapping were
--   GENERATED by parsing Locations.py with Python (ap_id = short_location_id +
--   118000000, verified consistent for all 24 entries), not hand-copied. The RAM
--   addresses + bit/transition logic below are replicated EXACTLY from the
--   official connector_adventure.lua. Loads crash-free on any cartridge and
--   self-disables on a non-Adventure ROM.
--   Source URL: https://github.com/ArchipelagoMW/Archipelago/tree/main/worlds/adventure
--               https://github.com/ArchipelagoMW/Archipelago/blob/main/data/lua/connector_adventure.lua
--
-- MEMORY MODEL (BizHawk Atari 2600 domains — EXACTLY as the official connector)
-- ────────────────────────────────────────────────────────────────────────────
--   The Atari 2600 has just 128 bytes of RAM. The official connector reads it via
--   the "System Bus" domain (it calls memory.usememorydomain("System Bus") at
--   start and then u8(addr) — common.lua's u8 reads the current domain). Low
--   addresses (0x80-0xFF) are the 2600 RAM page; the 4 KB cartridge ROM is mapped
--   at 0xF000-0xFFFF on the System Bus. The connector ALSO uses "Main RAM" for raw
--   128-byte block reads (uRangeRam → read_bytes_as_array(addr, n, "Main RAM")).
--   This module uses "System Bus" — the connector's primary domain — for every
--   address below, matching it byte-for-byte.
--
--   KEY ADDRESSES (System Bus, from connector_adventure.lua):
--     PlayerRoomAddr  = 0x8A   current room; 0x00 == "number room" (not in play)
--     WinAddr         = 0xDE   victory flag — nonzero (0xFF) once the chalice is
--                              returned to the yellow castle (the WIN / goal)
--     DragonState[]   = {0xA8 Rhindle, 0xAD Yorgle, 0xB2 Grundle}
--                              per-dragon state byte: 1 == that dragon is DEAD,
--                              2 == that dragon ate the player
--
--   ROM IDENTITY: Adventure carries NO "ARCHIPELAGO" magic string. The reference
--   client validates the cartridge by SHA-256 of the 4 KB ROM region
--   (memory.hash_region(0xF000, 0x1000, "System Bus")) against the patched ROM's
--   own hash. A fixed signature string therefore does not exist; instead we use a
--   tiny, name-independent STRUCTURAL fingerprint that is true of every Adventure
--   ROM (vanilla and AP-patched alike — the AP delta only tweaks item/room data,
--   speeds and a few switch bytes, never these): the item-table marker byte and
--   the player-slot byte the connector itself reads. See rom_is_adventure().
--
-- WHAT THIS DOES (mirrors connector_adventure.lua's detection, the RAM-only part)
--   • poll(): the FAITHFUL, source-exact, RAM-DERIVABLE checks —
--       – DRAGON SLAYS: when a DragonState byte transitions to 1 (dead), report
--         AP id 118000000 + (0xD0 + dragon_index)  (Rhindle 0xD0, Yorgle 0xD1,
--         Grundle 0xD2 — exactly the connector's `0xD0 + dragon_real_index`).
--         Gated on alive_mode() (player not in the number room AND not yet won)
--         so the title/number-room never reports a phantom slay, mirroring the
--         connector. Gated to the slot's server location set, and only when the
--         slay-dragon check option is actually in this seed (see GATE below).
--   • is_goal_complete(): WinAddr (0xDE) != 0 — the chalice-home victory the
--     connector sends as `victory = 1`. The DEFAULT and only Adventure goal.
--   • receive_item(): NO-OP (documented). items_handling = 0b111.
--
-- GATE — the 21 room/item-pickup location checks are NOT reported here, on purpose
-- ─────────────────────────────────────────────────────────────────────────────
--   Adventure's remaining 21 checks (Blue Labyrinth, Catacombs, the castle vaults,
--   the credits room, …) are detected by the official connector ONLY with help
--   from PATCH DATA that the dedicated AdventureClient pushes to it over a TCP
--   socket: per-seed `foreign_items` (which room each multiworld item is rendered
--   in), `local_item_locations` (which carried object-id maps to which location)
--   and `autocollect_items`. The connector renders placeholder item objects into
--   rooms from that data and watches the carry slot (0x9D) / AP-item RAM (0xE7,
--   0xEA) to know WHICH location was collected. Without that per-seed mapping —
--   which the launcher's generic CHECK/GOAL/SYNC bridge does not deliver — those
--   pickups cannot be attributed to a location id from RAM alone, so reporting
--   them would be guesswork. They are intentionally GATED (documented) rather than
--   shipped wrong. The goal and the three dragon slays need no patch data and are
--   reported. Full multiworld coverage is the dedicated AdventureClient's job (the
--   plugin documents this; ChecksImplemented reflects partial-but-correct).
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "adventure"

local ADDRESSES_VERIFIED = true   -- tables generated from worlds/adventure source

-- ── Memory domain (BizHawk Atari 2600) ────────────────────────────────────────
-- "System Bus" is the official connector's primary domain (it sets it once and
-- reads every byte through it). 2600 RAM is mirrored into the low System-Bus
-- addresses; the 4 KB ROM lives at 0xF000+.
local SYSTEM_BUS = "System Bus"

-- ── Addresses / constants (connector_adventure.lua + worlds/adventure) ────────
local PLAYER_ROOM_ADDR = 0x8A          -- 0x00 == number room (not in play mode)
local WIN_ADDR         = 0xDE          -- nonzero == victory (chalice home) → goal
local DRAGON_STATE     = { 0xA8, 0xAD, 0xB2 }  -- Rhindle, Yorgle, Grundle
local DRAGON_DEAD      = 1             -- state byte value when that dragon is slain
local DRAGON_BASE_SHORT = 0xD0         -- short_location_id of "Slay Rhindle"; +index
local BASE_ID          = 118000000     -- base_location_id (== base_adventure_item_id)

-- ROM structural fingerprint (name-independent; true of every Adventure ROM).
--   ItemTableStart (0xFE9D) is the first byte of the static item-data table the
--   connector indexes (ItemTableStart = 0xfe9d). In a real Adventure ROM this is
--   a meaningful, non-trivial byte; on a blank/short cartridge the System-Bus
--   read returns 0x00/0xFF mirrors. We pair it with a second ROM-region read so a
--   single coincidental value can't false-positive. This is a heuristic identity
--   check (Adventure has no AP magic string — the reference client uses a SHA-256
--   of the whole 4 KB ROM, which a per-frame Lua poll should not recompute), kept
--   deliberately permissive: its only job is to keep the module idle on a totally
--   wrong cartridge, never to reject a valid Adventure dump.
local ITEM_TABLE_START = 0xFE9D
local ROM_REGION_LO    = 0xF000        -- start of the 4 KB cartridge ROM window

-- ── Detectable location table (GENERATED from worlds/adventure/Locations.py) ──
-- ap_id -> short_location_id. 24 entries. ap_id = short_location_id + 118000000
-- (verified consistent for every entry). The three dragon-slay ids are the only
-- ones this module reports from RAM (see the GATE note in the header); the rest
-- are listed for reference / future patch-data wiring but are NOT polled.
local LOC = {
  [118000004]=4,[118000006]=6,[118000009]=9,[118000012]=12,[118000014]=14,[118000015]=15,
  [118000016]=16,[118000017]=17,[118000018]=18,[118000019]=19,[118000021]=21,[118000023]=23,
  [118000025]=25,[118000026]=26,[118000027]=27,[118000028]=28,[118000029]=29,[118000030]=30,
  [118000181]=181,[118000183]=183,[118000190]=190,[118000208]=208,[118000209]=209,[118000210]=210,
}

-- The RAM-derivable dragon-slay AP ids (Rhindle, Yorgle, Grundle), in DragonState
-- order. ap_id = BASE_ID + (DRAGON_BASE_SHORT + index).
local DRAGON_AP_ID = {
  BASE_ID + DRAGON_BASE_SHORT + 0,   -- Rhindle  → 118000208
  BASE_ID + DRAGON_BASE_SHORT + 1,   -- Yorgle   → 118000209
  BASE_ID + DRAGON_BASE_SHORT + 2,   -- Grundle  → 118000210
}

-- ── State ─────────────────────────────────────────────────────────────────────
local reported          = {}    -- ap_id -> true once returned from poll()
local server_locations  = nil   -- set of ap_ids the server expects (nil = all)
local rom_ok            = nil   -- cached ROM-identity result
local last_dragon_state = { 0, 0, 0 }   -- previous frame's DragonState bytes
local mem               = {}
local log_fn            = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[adventure] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8 = memory.read_u8 or memory.readbyte
  return mem.read_u8 ~= nil
end

local function read_u8(addr, domain)
  if not mem.read_u8 then return nil end
  local ok, v = pcall(mem.read_u8, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, addr)            -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

-- ── ROM identity (heuristic — Adventure has no AP signature string) ───────────
-- Keep the module idle on an obviously-wrong cartridge without ever rejecting a
-- valid Adventure dump. A real 4 KB Adventure ROM is mapped at 0xF000 on the
-- System Bus; on no cartridge / a stub the reads come back nil or as flat
-- 0x00/0xFF mirrors. We require: the item-table marker reads AND is not a flat
-- mirror, and the ROM window's first byte reads. Permissive by design.
local function rom_is_adventure()
  if rom_ok ~= nil then return rom_ok end
  local marker = read_u8(ITEM_TABLE_START, SYSTEM_BUS)
  local rom0   = read_u8(ROM_REGION_LO, SYSTEM_BUS)
  if marker == nil or rom0 == nil then
    return false                                 -- not readable yet; retry next poll
  end
  -- A flat all-0x00 or all-0xFF item-table marker means there's no real ROM here.
  if (marker == 0x00 and rom0 == 0x00) or (marker == 0xFF and rom0 == 0xFF) then
    rom_ok = false
    log("no Adventure ROM detected (flat ROM window) — detection idle")
    return false
  end
  rom_ok = true
  log("Adventure ROM accepted (structural fingerprint present)")
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end
  return server_locations[ap_id] == true
end

-- ── Detection gate (mirrors connector_adventure.lua alive_mode) ───────────────
-- alive_mode = player NOT in the number room (PlayerRoomAddr ~= 0) AND not won
-- (WinAddr == 0). The connector only reports locations checked in this state.
local function alive_mode()
  local room = read_u8(PLAYER_ROOM_ADDR, SYSTEM_BUS)
  local win  = read_u8(WIN_ADDR, SYSTEM_BUS)
  if room == nil or win == nil then return false end
  return room ~= 0x00 and win == 0x00
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " known locations (" .. #DRAGON_AP_ID ..
      " RAM-derivable dragon-slay checks reported; room/item pickups gated)")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_adventure() then return new end
  if not alive_mode() then return new end

  -- DRAGON SLAYS (source-exact, RAM-only). Report when a DragonState byte
  -- transitions to DRAGON_DEAD (1), exactly as the connector keys off
  -- last_dragon_state vs new state. Only when the seed actually has that
  -- slay-check location in its server set (the slay-dragon option gates it);
  -- `wanted()` enforces that automatically — a seed with the checks off simply
  -- won't list these ids, so they are never sent.
  for index, addr in ipairs(DRAGON_STATE) do
    local state = read_u8(addr, SYSTEM_BUS) or 0
    local ap_id = DRAGON_AP_ID[index]
    if last_dragon_state[index] ~= DRAGON_DEAD and state == DRAGON_DEAD then
      if not reported[ap_id] and wanted(ap_id) then
        reported[ap_id] = true
        new[#new + 1] = ap_id
        log("dragon slain (index " .. (index - 1) .. ") → ap_id " .. ap_id)
      end
    end
    last_dragon_state[index] = state
  end

  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_adventure() then return false end
  -- Victory: WinAddr (0xDE) becomes nonzero (0xFF) when the chalice is returned
  -- to the yellow castle — the connector's `victory = 1`. The default & only goal.
  local win = read_u8(WIN_ADDR, SYSTEM_BUS)
  return win ~= nil and win ~= 0x00
end

-- Remote items: items_handling = 0b111 — the AP server drives ALL item delivery.
-- Adventure's reference path delivers items by having the dedicated AdventureClient
-- feed an inventory queue to connector_adventure.lua over its socket, which then
-- injects each item into the carry slot (0x9D) under tight frame/input guards.
-- That patch-data + socket pipeline is the dedicated client's, not this generic
-- bridge's; applying items by guessing RAM here would be a wrong write. No-op
-- (never a wrong write), documented — matching the project's deferred-until-
-- verifiable rule. Checks + goal flow regardless.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
